"""A headless terminal emulator implementing the BaseTerminal interface.

Starts an interactive bash shell attached to a pseudo-terminal (PTY) and
emulates a real terminal screen using ``pyte``.  Keystrokes (including control
characters such as ``\x03`` for Ctrl-C) are written to the PTY, and the output
is parsed into an in-memory screen buffer that can be inspected at any time.
"""

import os
import pty
import select
import shutil
import signal
import threading
import time

import pyte

from base_terminal import BaseTerminal


class HeadlessTerminal(BaseTerminal):
    """An in-memory, headless terminal running an interactive bash shell."""

    def __init__(
        self,
        rows: int = 40,
        cols: int = 120,
        shell: str = "/bin/bash",
        env: dict | None = None,
        cwd: str | None = None,
    ) -> None:
        self.rows = rows
        self.cols = cols

        # In-memory screen emulation.
        self._screen = pyte.Screen(cols, rows)
        self._stream = pyte.ByteStream(self._screen)
        self._lock = threading.Lock()

        # Build the child environment.
        child_env = dict(os.environ)
        child_env.setdefault("TERM", "xterm-256color")
        child_env["LINES"] = str(rows)
        child_env["COLUMNS"] = str(cols)
        if env:
            child_env.update(env)

        shell_path = shutil.which(shell) or shell

        # Fork a child attached to a new PTY.
        pid, master_fd = pty.fork()
        if pid == 0:
            # Child process: become the interactive shell.
            try:
                if cwd:
                    os.chdir(cwd)
                # ``-i`` forces interactive mode so bash sources ~/.bashrc and
                # gives us job control, line editing, prompts, etc.
                os.execvpe(shell_path, [shell_path, "-i"], child_env)
            except Exception:
                os._exit(127)

        # Parent process.
        self.pid = pid
        self._master_fd = master_fd
        self._set_winsize(rows, cols)

        self._closed = False
        # Background reader thread keeps the screen buffer up to date.
        self._reader = threading.Thread(target=self._read_loop, daemon=True)
        self._reader.start()

        # Give the shell a moment to start up and source its rc files.
        time.sleep(0.3)

    # -- Internal helpers ---------------------------------------------------

    def _set_winsize(self, rows: int, cols: int) -> None:
        import fcntl
        import struct
        import termios

        winsize = struct.pack("HHHH", rows, cols, 0, 0)
        try:
            fcntl.ioctl(self._master_fd, termios.TIOCSWINSZ, winsize)
        except OSError:
            pass

    def _read_loop(self) -> None:
        while True:
            try:
                ready, _, _ = select.select([self._master_fd], [], [], 0.1)
            except (OSError, ValueError):
                break
            if not ready:
                continue
            try:
                data = os.read(self._master_fd, 65536)
            except OSError:
                break
            if not data:
                break
            with self._lock:
                self._stream.feed(data)
        self._closed = True

    # -- Public API ---------------------------------------------------------

    def send_keystrokes(self, keystrokes: str, wait_sec: float = 0.0) -> None:
        """Send keystrokes to the terminal.

        Args:
            keystrokes: The characters to send.  May include control
                sequences such as ``"\\x03"`` (Ctrl-C) or ``"\\n"`` (Enter).
            wait_sec: How long to wait after sending for output to settle.
        """
        if self._closed:
            raise RuntimeError("Terminal has been closed.")
        data = keystrokes.encode("utf-8", errors="surrogateescape")
        os.write(self._master_fd, data)
        if wait_sec > 0:
            time.sleep(wait_sec)

    # Convenience: typing a command and pressing Enter.
    def send_command(self, command: str, wait_sec: float = 0.0) -> None:
        self.send_keystrokes(command + "\n", wait_sec=wait_sec)

    def get_screen(self) -> str:
        """Return the current visible screen contents as text."""
        with self._lock:
            lines = self._screen.display
        return "\n".join(line.rstrip() for line in lines).rstrip("\n")

    # Aliases commonly expected by callers.
    def read_screen(self) -> str:
        return self.get_screen()

    def read_output(self) -> str:
        return self.get_screen()

    @property
    def display(self) -> list[str]:
        with self._lock:
            return list(self._screen.display)

    @property
    def screen(self) -> pyte.Screen:
        return self._screen

    @property
    def cursor(self):
        return self._screen.cursor

    def is_alive(self) -> bool:
        try:
            pid, _ = os.waitpid(self.pid, os.WNOHANG)
            return pid == 0
        except (ChildProcessError, OSError):
            return False

    def close(self) -> None:
        """Terminate the shell and release resources."""
        if getattr(self, "_closed_fully", False):
            return
        try:
            os.kill(self.pid, signal.SIGHUP)
        except (ProcessLookupError, OSError):
            pass
        try:
            os.close(self._master_fd)
        except OSError:
            pass
        try:
            os.waitpid(self.pid, 0)
        except (ChildProcessError, OSError):
            pass
        self._closed = True
        self._closed_fully = True

    def __enter__(self) -> "HeadlessTerminal":
        return self

    def __exit__(self, *exc) -> None:
        self.close()

    def __del__(self) -> None:
        try:
            self.close()
        except Exception:
            pass

